INSERT INTO motion (id, description, video_url) VALUES
    (1, '', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20160325/281631/MOV000277619_700X466.mp4'),
    (2, '', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20200826/736361/MOV000259287_700X466.mp4'),
    (3, '오른 주먹의 1지를 펴서 바닥을 이마 중앙에 댔다가 내리며 1지를 접고 5지를 펴서 왼 손바닥에 세운다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20160325/277326/MOV000275724_700X466.mp4'),
    (4, '두 손으로 지팡이를 잡고 뒤로 밀어젖히는 동작을 한다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20191015/627714/MOV000255556_700X466.mp4'),
    (5, '오른손의 1·5지 끝을 맞대어 동그라미를 만들고 그 끝으로 왼주먹의 손목 등을 스쳐 올린다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20201211/785379/MOV000357040_700X466.mp4'),
    (6, '두 손을 손끝이 밖으로 손등이 위로 향하게 하여 맞댄 다음, 옆으로 벌리다가 손목을 돌려 밑으로 약간 내린다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20191021/629718/MOV000247936_700X466.mp4'),
    (7, '두 손으로 밧줄을 잡고 있다가 놓치는 동작 (밧줄을 놓는 경우).', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20220811/1009783/MOV000360080_700X466.mp4'),
    (8, '손등이 위로 향하게 쥔 왼 주먹의 손목등에 오른 주먹의 1지를 펴서 모로 세워 댔다가 시계 바늘이 도는 방향으로 한 바퀴 돌려 다시 댄다(한 시간을 나타내는 경우).', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20220811/1009784/MOV000360081_700X466.mp4'),
    (9, '오른 주먹의 1지를 펴서 구부려 왼 주먹의 4지 등에 걸어 안으로 당긴다(남자의 경우).', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20221014/1040301/MOV000360703_700X466.mp4'),
    (10, '왼손을 손등이 밖으로 손끝이 오른쪽으로 향하게 배 앞에 내놓고 오른손을 손등이 밖으로 손끝이 왼쪽으로 향하게 하여 배에 댔다가 내밀어 왼 손바닥에 댄다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20191101/633269/MOV000260438_700X466.mp4'),
    (11, '손끝이 오른쪽으로 향하게 모로 세운 왼 손바닥에 오른손의 5지를 대고 나머지 손가락을 왼 손등에 대고 좌우로 반원을 그리며 문지른다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20191101/633270/MOV000260439_700X466.mp4'),
    (12, '오른 주먹의 1지를 펴서 치아를 가리킨 다음, 두 손바닥을 이마 중앙에서 겹쳤다가 양옆으로 돌린다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20221017/1041458/MOV000360791_700X466.mp4'),
    (13, '손끝이 위로 향하게 편 두 손을 얼굴 앞에서 아래로 내리면서 손끝을 모아 두 손의 손가락 등을 맞댄다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20160325/284617/MOV000282015_700X466.mp4'),
    (14, '오른 주먹을 쥐고 팔을 구부려 당긴다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20191007/624871/MOV000241093_700X466.mp4'),
    (15, '두 손을 약간 구부려 가슴 앞에서 상하로 마주 보게 하여 서로 엇갈리게 돌린다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20200825/735590/MOV000248300_700X466.mp4'),
    (16, '두 손을, 손끝이 아래로 향하게 하여 4지 옆면이 닿게 배 양옆에 댔다가 아래로 힘주어 내린 다음, 손바닥이 아래로 향하게 반쯤 구부린 오른손을 가슴 앞에서 약간 내리다가 멈춘다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20191007/625061/MOV000248318_700X466.mp4'),
    (17, '오른손의 2·3·5지 끝 바닥을 맞대고 세운 오른팔의 팔꿈치를 왼 손바닥으로 받치고 오른팔을 전후로 두 번 움직인다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20240118/1261176/MOV000361394_700X466.mp4'),
    (18, '오른 주먹을 오른쪽 귀 밑에서 1·2·5지를 튕기며 밖으로 내민다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20190918/615451/MOV000237701_700X466.mp4'),
    (19, '오른 손바닥으로 가슴과 배에 크게 원을 그린 다음, 손끝이 밖으로 손바닥이 위로 향하게 편 두 손을 가슴 앞에서 약간 위로 올리며 밖으로 내민다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20221013/1039332/MOV000360349_700X466.mp4'),
    (20, '오른 주먹의 1지를 펴서 끝으로 머리 오른쪽을 가리킨 다음, 오른손의 1·2·3·4지 끝을 5지에 모아 대고 끝이 눈으로 향하게 하여 왼쪽으로 두 바퀴 돌린다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20221024/1044175/MOV000361147_700X466.mp4'),
    (21, '손등이 밖으로 향하게 펴서 모로 세운 왼손의 손가락을 오른손으로 잡아 밖으로 당긴 다음, 두 주먹의 4·5지를 펴서 끝이 위로 향하게 맞대고 세워 좌우로 두 번 약간 돌리며 벌린다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20220801/1004770/MOV000359707_700X466.mp4'),
    (22, '오른 주먹을 1·5지 옆면이 턱에 닿게 대고 전후로 움직인다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20191029/632295/MOV000254102_700X466.mp4'),
    (23, '왼손으로 지숫자 ‘12’를, 오른손으로 지숫자 ‘25’를 표시한 다음, 손등이 아래로 향하게 가볍게 쥔 두 주먹을 위로 올리며 손가락을 활짝 편다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20201211/785504/MOV000357150_700X466.mp4'),
    (24, '오른 주먹의 1·2·3지를 펴서 벌려 반쯤 구부려 바닥이 밖으로 향하게 세워 좌우로 약간 흔든다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20220811/1009736/MOV000360033_700X466.mp4'),
    (25, '왼 주먹의 1·2·3지를 펴서 끝이 오른쪽으로 향하게 모로 세우고, 그 밑에 오른 주먹의 1지를 펴서 끝이 왼쪽으로 향하게 모로 세운 다음, 손등이 아래로 향하게 가볍게 쥔 두 주먹을 위로 올리며 활짝 편다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20200824/734994/MOV000254653_700X466.mp4'),
    (26, '손끝이 위로 향하게 편 오른 손바닥으로 오른뺨을 살짝 때리며 왼쪽으로 내리고 얼굴도 왼쪽으로 조금 돌린다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20200825/735419/MOV000245002_700X466.mp4'),
    (27, '오른 주먹의 5지를 펴서 세워 약간 위로 올린다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20200819/731439/MOV000244760_700X466.mp4'),
    (28, '1·5지 끝을 맞대고 등이 위로 향하게 쥔 두 주먹을 가슴 앞에서 간격을 유지하며 동시에 오른쪽으로 옮긴다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20220802/1005906/MOV000359908_700X466.mp4'),
    (29, '1·5지 끝을 맞대어 동그라미를 만든 오른손을 손등이 위로 향하게 쥔 왼 주먹의 손목 위에서 밖으로 내밀며 편다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20191021/629579/MOV000250265_700X466.mp4'),
    (30, '왼손의 5지와 나머지 손가락으로 ‘ㄷ’자 모양을 만들어 끝이 오른쪽으로 향하게 모로 세우고,손끝이 아래로 향하게 편 오른 손가락을 왼 손가락 사이에 옆으로 두 번 넣었다 뺀 다음,오른손의 1·5지 끝을 맞대어 동그라미를 만들어 왼 손바닥으로 내리며 1·5지를 편다', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20221012/1038680/MOV000360178_700X466.mp4'),
    (31, '두 주먹의 1·5지를 펴서 왼 주먹의 5지 등에 오른 주먹의 1지 끝을 두 번 댄다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20200824/735166/MOV000247782_700X466.mp4'),
    (32, '손등이 위로 향하게 편 두 손의 2·5지 끝을 맞댔다 뗐다 하며 밖으로 내민다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20221101/1047253/MOV000361195_700X466.mp4'),
    (33, '왼 손바닥을 오른쪽 가슴에 대고 오른 손바닥으로 가슴과 배에 크게 원을 그린다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20200824/735159/MOV000247876_700X466.mp4'),
    (34, '오른손을, 손가락 등이 위로 향하게 “ㄱ”자 모양으로 구부려 머리 오른쪽과 관자놀이에 차례로 대었다가, 두 주먹의 4·5지를 펴서 끝이 위로 향하게 맞대고 세워 양옆으로 벌린다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20200821/733052/MOV000242538_700X466.mp4'),
    (35, '오른 손바닥으로 머리 오른쪽을 스쳐 내리다가 손바닥을 반쯤 구부려 관자놀이에 댄 다음, 손가락을 벌려 반쯤 구부리고 손등이 위로 향하게 편 두 손의 손가락 등을 두 번 부딪친다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20220811/1009620/MOV000359954_700X466.mp4'),
    (36, '오른 주먹의 5지 끝에 1·2지를 대고 끝이 콧구멍으로 향하게 하였다가 밖으로 1·2지를 튕겨 내며 손가락을 벌려 편다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20200820/732530/MOV000246592_700X466.mp4'),
    (37, '위로 향하게 편 왼 손등에 오른손의 2지를 댔다가 손바닥을 댄 다음, 오른손의 1·5지 끝을 맞대어 동그라미를 만들어 끝으로 왼 손바닥을 손목에서 손끝으로 스쳐내는 동작을 두 번 반복하고, 오른 주먹의 1지를 펴서 세워 옆면을 입에 댔다가 밖으로 내민다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20160407/252642/MOV000264528_700X466.mp4'),
    (38, '오른손을 펴서 등이 밖으로 향하게 세워 오른쪽 어깨 너머로 넘긴다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20160407/252633/MOV000264493_700X466.mp4'),
    (39, '오른 주먹의 1·5지를 펴서 약간 구부려 오른쪽 어깨 높이에서 가슴 앞으로 힘주어 내린 다음, 오른손의 1·5지 끝을 맞대어 목에서 입으로 올려 내민다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20160325/285658/MOV000285401_700X466.mp4'),
    (40, '두 주먹의 4지를 펴서 등이 밖으로 향하게 하여 끝을 상하로 맞댔다가 뗀다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20200825/735445/MOV000260292_700X466.mp4'),
    (41, '손바닥이 아래로 손끝이 밖으로 향하게 편 왼 손바닥을 모로 세운 오른손의 4지 밑면으로 스쳐낸다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20200825/735778/MOV000260294_700X466.mp4'),
    (42, '손끝이 옆으로 손등이 위로 향하게 편 오른손 밑에 같은 모양의 왼손을 놓고 두 손목을 동시에 전후로 돌리면서 내린다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20200821/733677/MOV000260296_700X466.mp4'),
    (43, '5지를 펴서 세운 두 주먹을 맞댔다가 왼손은 그대로 두고 오른손만 안으로 당긴다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20200825/735447/MOV000260307_700X466.mp4'),
    (44, '5지를 접고 1·2·3·4지를 벌려 끝이 왼쪽으로, 등이 밖으로 향하게 한다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20220811/1009763/MOV000360060_700X466.mp4'),
    (45, '왼 주먹의 5지를 펴서 바닥이 밖으로 향하게 세우고, 그 등에서 오른손의 2·3·5지 끝을 맞대어 오른쪽으로 두 바퀴 돌린 다음, 손등이 위로 향하게 편 왼 손바닥 밑으로 손등이 위로 손끝이 밖으로 향하게 편 오른손을 왼손 밖에서 왼손 밑으로 당기며 주먹을 쥔 다음, 오른 주먹을 5지를 펴서 끝을 코 오른쪽에 댔다가 왼 손바닥에 내려 세운다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20221024/1044193/MOV000361157_700X466.mp4'),
    (46, '손등이 아래로 향하게 편 왼 손등에 오른 손등을 댔다가 아래로 내린 다음, 두 주먹의 4·5지를 펴서 끝이 위로 향하게 맞대고 세워 양옆으로 두 번 약간 돌리며 벌린다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20221012/1038759/MOV000360224_700X466.mp4'),
    (47, '오른 주먹의 1·2지를 펴서 벌려 끝이 아래로 등이 밖으로 향하게 하여 왼 손바닥에 올려놓는다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20221020/1042797/MOV000361041_700X466.mp4'),
    (48, '손바닥이 위로 향하게 편 왼 손바닥에 오른 주먹의 1·2지를 구부려 댄다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20200818/730459/MOV000248402_700X466.mp4'),
    (49, '왼 손바닥에, 1지를 펴고 가볍게 쥔 오른 주먹을 모로 세워 놓고 1지를 좌우로 흔든다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20200821/733721/MOV000248948_700X466.mp4'),
    (50, '오른 주먹의 1지를 펴서 바닥이 밖으로 향하게 세워 머리 오른쪽에 대고 두 번 오르내린다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20191029/632331/MOV000257008_700X466.mp4'),
    (51, '손바닥이 위로 향하게 편 왼손 약간 위에, 손등이 위로 향하게 쥔 오른 주먹을 놓고 두 손을 동시에 안으로 당긴다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20200825/735597/MOV000247610_700X466.mp4'),
    (52, '오른 주먹의 1·5지로 오른쪽 카이젤 수염을 오른쪽으로 올리는 동작을 한다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20221024/1044176/MOV000361148_700X466.mp4'),
    (53, '오른 주먹의 1·2지를 펴서 겹쳐 바닥이 밖으로 향하게 하여 오른쪽 눈 밑에 세워 두 번 튕긴다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20190918/615432/MOV000234816_700X466.mp4'),
    (54, '두 주먹의 5지 손톱을 맞대고 상하로 약간 흔든다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20191029/632454/MOV000250297_700X466.mp4'),
    (55, '손바닥이 위로 손끝이 밖으로 향하게 편 오른손을 안으로 당기면서 손끝을 맞댄다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20191011/626623/MOV000253492_700X466.mp4'),
    (56, '두 손을 벌려 상하로 흔든다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20191028/631986/MOV000248816_700X466.mp4'),
    (57, '두 손을 펴서 4지 옆면으로 배를 두 번 스쳐 올린다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20220802/1005833/MOV000359851_700X466.mp4'),
    (58, '손바닥이 위로 손끝이 오른쪽으로 향하게 편 왼 손바닥에 오른 주먹을 바닥이 닿게 올려놓고 좌우로 움직인다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20200824/735055/MOV000250737_700X466.mp4'),
    (59, '동그랗게 쥐고 모로 세운 왼 주먹의 1·5지 사이에 오른 주먹의 1지를 펴서 넣은 다음, 오른 주먹의 1지를 펴서 세워 옆면을 입에 댔다가 밖으로 내민다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20221014/1040346/MOV000360746_700X466.mp4'),
    (60, '왼 주먹의 5지를 펴서 손바닥이 안으로 향하게 세우고, 그 바닥에 오른손을 펴서 바닥을 대고 좌우로 한 번 움직인 다음, 오른손의 1·5지 끝을 맞대어 동그라미를 만들어 끝이 아래로 향하게 하여 상하로 두 번 움직인다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20200812/728285/MOV000236028_700X466.mp4'),
    (61, '오른 주먹의 1지를 펴서 반쯤 구부려 끝으로 머리 오른쪽을 두 번 친 다음, 두 손의 손끝이 밖으로 향하게 하여 손뼉을 두 번 친다.', 'http://sldict.korean.go.kr/multimedia/multimedia_files/convert/20200821/733452/MOV000246616_700X466.mp4'),
